"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[706929],{889565:e=>{e.exports=JSON.parse('{"tag":{"label":"cooking","permalink":"/dst-api-webdocs/docs/tags/cooking","allTagsPath":"/dst-api-webdocs/docs/tags","count":26,"items":[{"id":"game-scripts/prefabs/ancienttree_fruits","title":"Ancienttree Fruits","description":"Provides game logic for ancient tree fruits, including gem fruit temperature-based hatching, night vision fruit effects, and the night vision debuff component.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ancienttree_fruits"},{"id":"game-scripts/prefabs/campfire","title":"Campfire","description":"Manages a consumable fire source that provides heat, light, cooking capability, and hauntable behavior in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/campfire"},{"id":"game-scripts/components/cookable","title":"Cookable","description":"Enables an entity to be transformed into a cooked product when processed in a cooking station.","permalink":"/dst-api-webdocs/docs/game-scripts/components/cookable"},{"id":"game-scripts/cookbookdata","title":"Cookbookdata","description":"Manages player cookbook progression data including discovered foods, learned recipes, and UI filter settings.","permalink":"/dst-api-webdocs/docs/game-scripts/cookbookdata"},{"id":"game-scripts/components/cooker","title":"Cooker","description":"Validates and executes cooking operations for items placed on a cooking entity, ensuring required conditions are met and handling side effects like sound playback and event callbacks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/cooker"},{"id":"game-scripts/cooking","title":"Cooking","description":"Provides cooking recipe registration, ingredient value tracking, and recipe calculation utilities for all cooker entities.","permalink":"/dst-api-webdocs/docs/game-scripts/cooking"},{"id":"game-scripts/prefabs/dragonfurnace","title":"Dragonfurnace","description":"Manages the furnace\'s cooking, incineration, and hammering mechanics, including state transitions, sound handling, and loot generation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/dragonfurnace"},{"id":"game-scripts/prefabs/egg","title":"Egg","description":"Defines prefabs for raw, cooked, and rotten bird eggs, each with distinct properties including edibility, perishability, and fertilizer usability.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/egg"},{"id":"game-scripts/prefabs/elixir_container","title":"Elixir Container","description":"A portable storage container with three inventory slots, designed to hold items while being carried or opened by the player.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/elixir_container"},{"id":"game-scripts/prefabs/firepit","title":"Firepit","description":"A structure that provides a controllable fire source for cooking, heating, and light, fueled by consumable items and supporting charcoal production.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/firepit"},{"id":"game-scripts/prefabs/froglegs","title":"Froglegs","description":"A raw meat food item that can be dried or cooked, granting basic nutrition and sanity penalty when eaten raw.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/froglegs"},{"id":"game-scripts/prefabs/moon_mushroom","title":"Moon Mushroom","description":"Defines theprefab definitions and behaviors for raw and cooked Moon Mushroom items, including eating effects, cooking compatibility, perishability, and fuel use.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moon_mushroom"},{"id":"game-scripts/prefabs/portablecookpot","title":"Portablecookpot","description":"Manages the cooked pot\'s cooking state, container interaction, deployable behavior, and visual/sound feedback during cooking, burning, and dismantling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/portablecookpot"},{"id":"game-scripts/preparedfoods_warly","title":"Preparedfoods Warly","description":"Defines special cooked food recipes for Warly\'s portable cookpot that grant unique or unusual effects when consumed.","permalink":"/dst-api-webdocs/docs/game-scripts/preparedfoods_warly"},{"id":"game-scripts/preparednonfoods","title":"Preparednonfoods","description":"Provides a list of non-prefab crock pot recipes that reference externally defined prefabs.","permalink":"/dst-api-webdocs/docs/game-scripts/preparednonfoods"},{"id":"game-scripts/prefabs/quagmire_casseroledish","title":"Quagmire Casseroledish","description":"Creates inventory prefabs for Quagmire casserole dishes used in cooking.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_casseroledish"},{"id":"game-scripts/prefabs/quagmire_fish","title":"Quagmire Fish","description":"Creates quagmire-region fish prefabs with raw and cooked variants, including animation, inventory physics, and network support for Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_fish"},{"id":"game-scripts/prefabs/quagmire_mushrooms","title":"Quagmire Mushrooms","description":"Defines the raw and cooked quagmire mushroom prefabs, including their visual, physics, and game-state properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_mushrooms"},{"id":"game-scripts/prefabs/quagmire_pot","title":"Quagmire Pot","description":"Creates and registers prefabs for Quagmire cooking pots with configurable capacity and visual variants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_pot"},{"id":"game-scripts/prefabs/rock_avocado_fruit","title":"Rock Avocado Fruit","description":"Manages the lifecycle and interactivity of rock avocado plant variants, including harvesting, cooking, planting, and growth.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rock_avocado_fruit"},{"id":"game-scripts/prefabs/seeds","title":"Seeds","description":"Defines the \'seeds\' and \'seeds_cooked\' prefabs with associated components for use as raw or cooked food, bait, farm planting material, and ocean fishing lures.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/seeds"},{"id":"game-scripts/components/stewer","title":"Stewer","description":"Manages cooking and spoilage timers for stew pot entities, handling cooking progression, product generation, and spoilage logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/stewer"},{"id":"game-scripts/prefabs/trunk","title":"Trunk","description":"Creates the raw trunk item (summer, winter, cooked variants) for Koalephant, a meat-based food item with perishable and tradable properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trunk"},{"id":"game-scripts/prefabs/veggies","title":"Veggies","description":"Generates prefabs and logic for vegetables, their cooked/dried variants, oversized variants with weight-based physics and equippable functionality, and seed deployment mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/veggies"},{"id":"game-scripts/prefabs/wintersfeastcookedfoods","title":"Wintersfeastcookedfoods","description":"Generates prefabs for Winters Feast cooked foods, configuring them with finite uses and inventory interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wintersfeastcookedfoods"},{"id":"game-scripts/prefabs/wintersfeastoven","title":"Wintersfeastoven","description":"Implements the Winters Feast Oven, a multi-stage cooking station that requires science-based cooking steps and produces festive dishes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wintersfeastoven"}],"unlisted":false}}')}}]);